// 1. 함수 시그니처만 작성 → Tab으로 본문 자동 생성
function formatCurrency(amount: number, currency: string = 'KRW')
// Tab 누르면 →
function formatCurrency(amount: number, currency: string = 'KRW'): string {
  return new Intl.NumberFormat('ko-KR', {
    style: 'currency',
    currency,
  }).format(amount);
}

// 2. 주석 작성 → 구현 자동 생성
// 이메일 유효성을 검사하는 함수
